// Fecha y hora actual del servidor n8n en zona America/Bogota.
// Expone multiples formatos para que el agente los use como contexto.
const tz = 'America/Bogota';
const ahora = new Date();

const partes = ahora.toLocaleString('en-CA', {
  timeZone: tz,
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
});
const [fechaISO, horaFull] = partes.split(', ');
const horaActual = horaFull.slice(0,5);

const diasSemana = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

const base = new Date(fechaISO + 'T12:00:00');
const diaSemana = diasSemana[base.getDay()];
const dia = base.getDate();
const mes = meses[base.getMonth()];
const anio = base.getFullYear();
const fechaLegible = `${diaSemana} ${dia} de ${mes}`;

// Fecha maxima permitida (hoy + 5 dias)
const lim = new Date(base);
lim.setDate(lim.getDate() + 5);
const pad = n => String(n).padStart(2,'0');
const fechaLimiteISO = `${lim.getFullYear()}-${pad(lim.getMonth()+1)}-${pad(lim.getDate())}`;
const fechaLimiteLegible = `${diasSemana[lim.getDay()]} ${lim.getDate()} de ${meses[lim.getMonth()]}`;

return [{
  json: {
    ...$input.first().json,
    fechaISO,
    horaActual,
    diaSemana,
    fechaLegible,
    anio,
    fechaLimiteISO,
    fechaLimiteLegible,
    timezone: tz
  }
}];

